class Playground {
    async run(inputs) {
        let matrix;
        try {
            matrix = JSON.parse(inputs[0]);
        } catch (e) {
            this.log("Invalid JSON input");
            return 0;
        }

        const rows = matrix.length;
        const cols = rows > 0 ? matrix[0].length : 0;

        // 1. Initialize Slots
        this.grid.init(matrix);
        const visitedMatrix = Array.from({ length: rows }, () => Array(cols).fill(0));
        this.visited.init(visitedMatrix);
        this.vars.init([["Island Count", 0]]);
        this.callstack.init();
        this.recursionTree.init();

        this.rows = rows;
        this.cols = cols;
        let islandCount = 0;

        this.log("Starting scan of the grid...");
        await this.await();

        // 2. Iterate through grid
        for (let r = 0; r < rows; r++) {
            for (let c = 0; c < cols; c++) {
                this.grid.highlight(r, c, "#ffb703"); // Highlight current scanner position

                const cellValue = this.grid.getCell(r, c);
                const isVisited = this.visited.getCell(r, c);

                if (cellValue === "1" && isVisited === 0) {
                    islandCount++;
                    this.vars.put("Island Count", islandCount);
                    this.log(`New island found at (${r}, ${c})! Total islands: ${islandCount}`);
                    await this.await();

                    // Start DFS to mark entire island
                    await this.dfs(r, c);
                }

                this.grid.highlight(r, c, null); // Remove scanner highlight
            }
        }

        this.log(`Algorithm complete. Final count: ${islandCount}`);
        return islandCount;
    }

    async dfs(r, c) {
        const nodeId = `${r}-${c}`;

        // Strict Recursion Rules
        this.callstack.pushFrame("dfs", { r, c });
        this.recursionTree.enterNode(nodeId, `(${r},${c})`);

        // Mark as visited
        this.visited.setCell(r, c, 1);
        this.visited.highlight(r, c, "#00f5a0"); // Visited color
        this.grid.highlight(r, c, "#00e0ff");    // Current node color

        this.log(`DFS: Visiting land at (${r}, ${c})`);
        await this.await();

        const directions = [
            [0, 1],  // Right
            [1, 0],  // Down
            [0, -1], // Left
            [-1, 0]  // Up
        ];

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            // Check boundaries
            if (nr >= 0 && nr < this.rows && nc >= 0 && nc < this.cols) {
                const neighborVal = this.grid.getCell(nr, nc);
                const neighborVisited = this.visited.getCell(nr, nc);

                if (neighborVal === "1" && neighborVisited === 0) {
                    this.log(`Moving to neighbor (${nr}, ${nc})`);
                    await this.dfs(nr, nc);
                }
            }
        }

        // Backtracking / Finishing cell
        this.grid.highlight(r, c, "#00f5a0"); // Keep finished land highlighted as visited
        this.callstack.popFrame();
        this.recursionTree.exitNode();
    }
}
